   589→
   590→func parseServiceAccountKey(key interface{}) (serviceAccountQueueKey, error) {
   591→	queueKey, ok := key.(serviceAccountQueueKey)
   592→	if !ok || len(queueKey.namespace) == 0 || len(queueKey.name) == 0 || len(queueKey.uid) == 0 {
   593→		return serviceAccountQueueKey{}, fmt.Errorf("invalid serviceaccount key: %#v", key)
   594→	}
   595→	return queueKey, nil
   596→}
