   214→func (e *TokensController) queueSecretSync(obj interface{}) {
   215→	if secret, ok := obj.(*v1.Secret); ok {
   216→		e.syncSecretQueue.Add(makeSecretQueueKey(secret))
   217→	}
   218→}
