   220→func (e *TokensController) queueSecretUpdateSync(oldObj interface{}, newObj interface{}) {
   221→	if secret, ok := newObj.(*v1.Secret); ok {
   222→		e.syncSecretQueue.Add(makeSecretQueueKey(secret))
   223→	}
   224→}
