   510→func (e *TokensController) getSecret(ns string, name string, uid types.UID, fetchOnCacheMiss bool) (*v1.Secret, error) {
   511→	// Look up in cache
   512→	obj, exists, err := e.updatedSecrets.GetByKey(makeCacheKey(ns, name))
   513→	if err != nil {
   514→		return nil, err
   515→	}
   516→	if exists {
   517→		secret, ok := obj.(*v1.Secret)
   518→		if !ok {
   519→			return nil, fmt.Errorf("expected *v1.Secret, got %#v", secret)
   520→		}
   521→		// Ensure UID matches if given
   522→		if len(uid) == 0 || uid == secret.UID {
   523→			return secret, nil
   524→		}
   525→	}
   526→
   527→	if !fetchOnCacheMiss {
   528→		return nil, nil
   529→	}
   530→
   531→	// Live lookup
   532→	secret, err := e.client.CoreV1().Secrets(ns).Get(context.TODO(), name, metav1.GetOptions{})
   533→	if apierrors.IsNotFound(err) {
   534→		return nil, nil
   535→	}
   536→	if err != nil {
   537→		return nil, err
   538→	}
   539→	// Ensure UID matches if given
   540→	if len(uid) == 0 || uid == secret.UID {
   541→		return secret, nil
   542→	}
   543→	return nil, nil
   544→}
