   573→// serviceAccountQueueKey holds information we need to sync a service account.
   574→// It contains enough information to look up the cached service account,
   575→// or delete owned tokens if the service account no longer exists.
   576→type serviceAccountQueueKey struct {
   577→	namespace string
   578→	name      string
   579→	uid       types.UID
   580→}
   581→
   582→func makeServiceAccountKey(sa *v1.ServiceAccount) serviceAccountQueueKey {
   583→	return serviceAccountQueueKey{
   584→		namespace: sa.Namespace,
   585→		name:      sa.Name,
